mapper.select:
SELECT CODE, NAME, REMARK, USE_YN, DATE_FORMAT(FIRST_REG_DATE, '%Y-%m-%d %H:%i:%s') AS FIRST_REG_DATE, FIRST_REG_USER_ID, DATE_FORMAT(LAST_CHG_DATE, '%Y-%m-%d %H:%i:%s') AS LAST_CHG_DATE, LAST_CHG_USER_ID FROM COMMON_GROUP_CODE
AND CODE = #{code}
AND NAME LIKE CONCAT('%', #{name}, '%')
AND USE_YN = #{useYn}
AND FIRST_REG_DATE >= STR_TO_DATE(CONCAT(#{firstRegDate}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s')
AND FIRST_REG_DATE >= STR_TO_DATE(#{firstRegDate}, '%Y-%m-%d %H:%i:%s')
AND LAST_CHG_DATE <= STR_TO_DATE(CONCAT(#{lastChgDate}, ' 23:59:59'), '%Y-%m-%d %H:%i:%s')
AND LAST_CHG_DATE <= STR_TO_DATE(#{lastChgDate}, '%Y-%m-%d %H:%i:%s')
AND FIRST_REG_USER_ID = #{firstRegUserId}
AND LAST_CHG_USER_ID = #{lastChgUserId}
ORDER BY CODE ASC
